examples.code:
// 4-digit PIN in underline style
<CodeInput
  length={4}
  value={pin}
  onChangeText={setPin}
  variant="underline"
  onComplete={handlePinSubmit}
/>

// Success state after correct code entry
<CodeInput
  length={6}
  value={otp}
  onChangeText={setOtp}
  success={isVerified}
  disabled={isVerified}
/>

// Larger boxes for improved visibility
<CodeInput
  length={6}
  value={otp}
  onChangeText={setOtp}
  size="lg"
  accessibilityLabel="Verification code"
/>
